#[allow(unused_imports)]
use std::cmp::*;
#[allow(unused_imports)]
use std::collections::*;
use std::io::{Write, BufWriter};
// https://qiita.com/tanakh/items/0ba42c7ca36cd29d0ac8
macro_rules! input {
    ($($r:tt)*) => {
        let stdin = std::io::stdin();
        let mut bytes = std::io::Read::bytes(std::io::BufReader::new(stdin.lock()));
        let mut next = move || -> String{
            bytes
                .by_ref()
                .map(|r|r.unwrap() as char)
                .skip_while(|c|c.is_whitespace())
                .take_while(|c|!c.is_whitespace())
                .collect()
        };
        input_inner!{next, $($r)*}
    };
}

macro_rules! input_inner {
    ($next:expr) => {};
    ($next:expr, ) => {};

    ($next:expr, $var:ident : $t:tt $($r:tt)*) => {
        let $var = read_value!($next, $t);
        input_inner!{$next $($r)*}
    };
}

macro_rules! read_value {
    ($next:expr, ( $($t:tt),* )) => {
        ( $(read_value!($next, $t)),* )
    };

    ($next:expr, [ $t:tt ; $len:expr ]) => {
        (0..$len).map(|_| read_value!($next, $t)).collect::<Vec<_>>()
    };

    ($next:expr, chars) => {
        read_value!($next, String).chars().collect::<Vec<char>>()
    };

    ($next:expr, usize1) => {
        read_value!($next, usize) - 1
    };

    ($next:expr, [ $t:tt ]) => {{
        let len = read_value!($next, usize);
        (0..len).map(|_| read_value!($next, $t)).collect::<Vec<_>>()
    }};

    ($next:expr, $t:ty) => {
        $next().parse::<$t>().expect("Parse error")
    };
}

fn solve() {
    let out = std::io::stdout();
    let mut out = BufWriter::new(out.lock());
    macro_rules! puts {
        ($($format:tt)*) => (write!(out,$($format)*).unwrap());
    }
    input! {
        n: usize, m: usize, a: usize, b: usize,
        g0: i64, x: i64, y: i64, z: i64,
    }
    let mut d = vec![vec![0; m]; n];
    let mut state = g0;
    for i in 0..n {
        for j in 0..m {
            d[i][j] = state;
            state = (x * state + y) % z;
        }
    }
    let mut slide = vec![vec![0; m]; n];
    for i in 0..n {
        let mut st = VecDeque::<(i64, usize)>::new();
        for j in 0..m {
            if j >= b {
                while let Some(x) = st.pop_front() {
                    if x.1 > j - b {
                        st.push_front(x);
                        break;
                    }
                }
            }
            while let Some(x) = st.pop_back() {
                if x.0 < d[i][j] {
                    st.push_back(x);
                    break;
                }
            }
            st.push_back((d[i][j], j));
            slide[i][j] = st.front().unwrap().0;
        }
    }
    let mut ans = vec![vec![0; m]; n];
    for j in b - 1..m {
        let mut st = VecDeque::<(i64, usize)>::new();
        for i in 0..n {
            if i >= a {
                while let Some(x) = st.pop_front() {
                    if x.1 > i - a {
                        st.push_front(x);
                        break;
                    }
                }
            }
            while let Some(x) = st.pop_back() {
                if x.0 < slide[i][j] {
                    st.push_back(x);
                    break;
                }
            }
            st.push_back((slide[i][j], i));
            ans[i][j] = st.front().unwrap().0;
        }
    }
    let mut tot: i64 = 0;
    for i in a - 1..n {
        for j in b - 1..m {
            tot += ans[i][j];
        }
    }
    puts!("{}\n", tot);
}

fn main() {
    // In order to avoid potential stack overflow, spawn a new thread.
    let stack_size = 104_857_600; // 100 MB
    let thd = std::thread::Builder::new().stack_size(stack_size);
    thd.spawn(|| solve()).unwrap().join().unwrap();
}
